CanManager::CanManager() : m_isRunning(false) {}

void CanManager::startSimulation() {
  if (m_isRunning) {
    std::cout << "CAN simulation already running" << std::endl;
    return;
  }

  serverCanScheduler.startCanScheduler();
  serverCanListener.listenCanBus();
  m_isRunning = true;
  std::cout << "CAN simulation started" << std::endl;
}

void CanManager::stopSimulation() {
  m_isRunning = false;
  std::cout << "CAN simulation stopped" << std::endl;
}

bool CanManager::isRunning() const {
  return m_isRunning;
}

