CanMessageInfo CanManager::getMessageInfo(const std::string &message_name) const {
  const auto list = getMessageInfoList();
  for (const auto &info : list) {
    if (info.name == message_name) {
      return info;
    }
  }
  return CanMessageInfo{};
}

